export type ParsedAwardAchievementInstruction<
  TProgram extends string = typeof ONCHAIN_ACADEMY_PROGRAM_ADDRESS,
  TAccountMetas extends readonly AccountMeta[] = readonly AccountMeta[],
> = {
  programAddress: Address<TProgram>;
  accounts: {
    config: TAccountMetas[0];
    achievementType: TAccountMetas[1];
    achievementReceipt: TAccountMetas[2];
    minterRole: TAccountMetas[3];
    /** New achievement NFT keypair */
    asset: TAccountMetas[4];
    collection: TAccountMetas[5];
    recipient: TAccountMetas[6];
    recipientTokenAccount: TAccountMetas[7];
    xpMint: TAccountMetas[8];
    payer: TAccountMetas[9];
    minter: TAccountMetas[10];
    mplCoreProgram: TAccountMetas[11];
    tokenProgram: TAccountMetas[12];
    systemProgram: TAccountMetas[13];
  };
  data: AwardAchievementInstructionData;
};

export function parseAwardAchievementInstruction<
  TProgram extends string,
  TAccountMetas extends readonly AccountMeta[],
>(
  instruction: Instruction<TProgram> &
    InstructionWithAccounts<TAccountMetas> &
    InstructionWithData<ReadonlyUint8Array>,
): ParsedAwardAchievementInstruction<TProgram, TAccountMetas> {
  if (instruction.accounts.length < 14) {
    throw new SolanaError(
      SOLANA_ERROR__PROGRAM_CLIENTS__INSUFFICIENT_ACCOUNT_METAS,
      {
        actualAccountMetas: instruction.accounts.length,
        expectedAccountMetas: 14,
      },
    );
  }
  let accountIndex = 0;
  const getNextAccount = () => {
    const accountMeta = (instruction.accounts as TAccountMetas)[accountIndex]!;
    accountIndex += 1;
    return accountMeta;
  };
  return {
    programAddress: instruction.programAddress,
    accounts: {
      config: getNextAccount(),
      achievementType: getNextAccount(),
      achievementReceipt: getNextAccount(),
      minterRole: getNextAccount(),
      asset: getNextAccount(),
      collection: getNextAccount(),
      recipient: getNextAccount(),
      recipientTokenAccount: getNextAccount(),
      xpMint: getNextAccount(),
      payer: getNextAccount(),
      minter: getNextAccount(),
      mplCoreProgram: getNextAccount(),
      tokenProgram: getNextAccount(),
      systemProgram: getNextAccount(),
    },
    data: getAwardAchievementInstructionDataDecoder().decode(instruction.data),
  };
}
